+++ b/Users/jay/workspace/graphite/src/styles/animations.css
@@ -1,96 +1,96 @@
 /*
  * Graphite — Animation Styles
  * 
  * Motion should be subtle and purposeful. No decorative animations.
  * The app should feel instant.
  */

 /* Panel show/hide */
 @keyframes fadeSlideIn {
   from {
     opacity: 0;
     transform: translateY(6px);
   }
   to {
     opacity: 1;
     transform: translateY(0);
   }
 }

 @keyframes fadeSlideOut {
   from {
     opacity: 1;
     transform: translateY(0);
   }
   to {
     opacity: 0;
     transform: translateY(6px);
   }
 }

 /* Chat message entrance */
 .message-enter {
   animation: fadeSlideIn 300ms ease forwards;
 }

 /* Panel transitions */
 .panel-enter {
   animation: fadeSlideIn 200ms ease forwards;
 }

 .panel-exit {
   animation: fadeSlideOut 200ms ease forwards;
 }

 /* Chevron rotation for folder open/close */
 .chevron {
   transition: transform 150ms ease;
 }

 .chevron.open {
   transform: rotate(90deg);
 }

 /* Hover state transitions — applied to interactive elements */
 .hoverable {
   transition: background-color var(--transition-fast);
 }

 .hoverable:hover {
   background-color: var(--hover);
 }

 .hoverable:active {
   background-color: var(--active);
 }

 /* Button active state */
 .toggle-active {
   color: var(--accent);
   background-color: var(--accent-dim);
 }

 /* Subtle fade for loading states */
 @keyframes fadeIn {
   from {
     opacity: 0;
   }
   to {
     opacity: 1;
   }
 }

 .fade-in {
   animation: fadeIn 200ms ease forwards;
 }

 /* Resize handle highlight */
 .resize-handle {
   transition: background-color var(--transition-fast);
 }

 .resize-handle:hover,
 .resize-handle.active {
   background-color: var(--accent);
 }

