 /**
  * Graphite — TitleBar Component
  * 
  * Height: 46px
  * - Left: Hexagon icon + "GRAPHITE" wordmark
  * - Right: Preview, Companion toggles, Theme switcher, filename
  */

 import React from 'react';
 import { Hexagon, Preview as PreviewIcon, Sparkle } from '../../icons/Icons';
 import { usePanels } from '../Panels/PanelManager';
 import ThemeSwitcher from '../ThemeSwitcher/ThemeSwitcher';
 import './TitleBar.css';

 export default function TitleBar({ currentFile, isDirty = false }) {
   const { visibility, togglePanel } = usePanels();

   // Extract filename from path
   const fileName = currentFile 
     ? currentFile.split('/').pop() 
     : 'Untitled';

   return (
     <header className="title-bar drag-region">
       {/* Brand */}
       <div className="title-bar-brand no-drag">
         <Hexagon size={20} className="title-bar-logo" />
         <span className="title-bar-wordmark">GRAPHITE</span>
       </div>

       {/* Right side: toggles + theme switcher + filename */}
       <div className="title-bar-right no-drag">
         <div className="title-bar-toggles">
           <button
             className={`title-bar-toggle hoverable ${visibility['preview'] ? 'toggle-active' : ''}`}
             onClick={() => togglePanel('preview')}
             title="Toggle Preview"
           >
             <PreviewIcon size={16} />
             <span>Preview</span>
           </button>

           <button
             className={`title-bar-toggle hoverable ${visibility['ai-chat'] ? 'toggle-active' : ''}`}
             onClick={() => togglePanel('ai-chat')}
             title="Toggle Writing Companion"
           >
             <Sparkle size={16} />
             <span>Companion</span>
           </button>
         </div>

         <div className="title-bar-separator" />

         <ThemeSwitcher />

         <span className="title-bar-filename">
           {isDirty && <span className="title-bar-dirty-indicator">●</span>}
           {fileName}
         </span>
       </div>
     </header>
   );
 }

