 /**
  * Graphite — CodeMirror 6 Theme
  * 
  * Custom theme that reads from CSS variables so it automatically
  * updates when the app theme changes. No hardcoded colors.
  * 
  * Per spec:
  * - Font: JetBrains Mono, 14px, line-height 1.8
  * - Caret: --accent color
  * - No line numbers
  * - Soft word wrap
  */

 import { EditorView } from '@codemirror/view';

 /**
  * Get a CSS variable value from the document root
  */
 function cssVar(name) {
   return getComputedStyle(document.documentElement).getPropertyValue(name).trim();
 }

 /**
  * Create the Graphite editor theme
  * This returns a fresh theme extension that reads current CSS variable values
  */
 export function createGraphiteTheme(isDark = true) {
   return EditorView.theme({
     // Root editor styles
     '&': {
       height: '100%',
       fontSize: 'var(--font-editor-size)',
       backgroundColor: 'var(--bg-editor)',
     },

     // Scroller (contains the content)
     '.cm-scroller': {
       fontFamily: 'var(--font-editor)',
       lineHeight: '1.8',
       padding: '32px 40px',
       overflow: 'auto',
     },

     // Content area
     '.cm-content': {
       caretColor: 'var(--accent)',
       color: 'var(--text-primary)',
       padding: '0',
     },

     // All lines - ensure no underlines by default
     '.cm-line': {
       padding: '0',
       textDecoration: 'none',
     },

     // Ensure no underlines on any span inside lines
     '.cm-line span': {
       textDecoration: 'none',
     },

     // Cursor
     '.cm-cursor, .cm-dropCursor': {
       borderLeftColor: 'var(--accent)',
       borderLeftWidth: '2px',
     },

     // Selection
     '&.cm-focused .cm-selectionBackground, .cm-selectionBackground': {
       backgroundColor: 'var(--accent-dim)',
     },

     '.cm-selectionMatch': {
       backgroundColor: 'var(--accent-dim)',
     },

     // Active line highlight (subtle)
     '.cm-activeLine': {
       backgroundColor: 'transparent',
     },

     // Gutters (hidden - no line numbers)
     '.cm-gutters': {
       display: 'none',
     },

     // Placeholder text
     '.cm-placeholder': {
       color: 'var(--text-tertiary)',
       fontStyle: 'normal',
     },

     // Focus outline
     '&.cm-focused': {
       outline: 'none',
     },

     // Markdown-specific syntax highlighting
     '.cm-header': {
       color: 'var(--text-primary)',
       fontWeight: '600',
       textDecoration: 'none',
     },

     '.cm-header-1': {
       fontSize: '1.5em',
     },

     '.cm-header-2': {
       fontSize: '1.3em',
     },

     '.cm-header-3': {
       fontSize: '1.15em',
     },

     // Header markers (the # symbols)
     '.cm-heading-marker': {
       color: 'var(--text-tertiary)',
       fontWeight: '400',
     },

     '.cm-strong': {
       fontWeight: '600',
       color: 'var(--text-primary)',
     },

     '.cm-emphasis': {
       fontStyle: 'italic',
       color: 'var(--text-primary)',
     },

     '.cm-strikethrough': {
       textDecoration: 'line-through',
       color: 'var(--text-secondary)',
     },

     '.cm-link': {
       color: 'var(--accent)',
       textDecoration: 'none',
     },

     '.cm-url': {
       color: 'var(--text-tertiary)',
     },

     '.cm-code': {
       fontFamily: 'var(--font-mono)',
       backgroundColor: 'var(--hover)',
       borderRadius: '3px',
       padding: '1px 4px',
     },

     '.cm-quote': {
       color: 'var(--text-secondary)',
       fontStyle: 'italic',
     },

     '.cm-list': {
       color: 'var(--accent)',
     },

     '.cm-hr': {
       color: 'var(--border)',
     },

     '.cm-image': {
       color: 'var(--accent)',
     },

     // Search matches
     '.cm-searchMatch': {
       backgroundColor: 'var(--accent-dim)',
       outline: '1px solid var(--accent)',
     },

     '.cm-searchMatch.cm-searchMatch-selected': {
       backgroundColor: 'var(--accent)',
     },

     // Tooltips
     '.cm-tooltip': {
       backgroundColor: 'var(--bg-secondary)',
       border: '1px solid var(--border)',
       borderRadius: '6px',
       color: 'var(--text-primary)',
     },

     // Panels (like search panel)
     '.cm-panels': {
       backgroundColor: 'var(--bg-panel)',
       color: 'var(--text-primary)',
     },

     '.cm-panel': {
       padding: '8px 12px',
     },

     '.cm-panel input': {
       backgroundColor: 'var(--bg-secondary)',
       border: '1px solid var(--border)',
       borderRadius: '4px',
       color: 'var(--text-primary)',
       padding: '4px 8px',
     },

     '.cm-panel button': {
       backgroundColor: 'var(--bg-secondary)',
       border: '1px solid var(--border)',
       borderRadius: '4px',
       color: 'var(--text-primary)',
       padding: '4px 12px',
       cursor: 'pointer',
     },

     '.cm-panel button:hover': {
       backgroundColor: 'var(--hover)',
     },
   }, { dark: isDark });
 }

 /**
  * Base theme configuration (non-color styles)
  */
 export const graphiteBaseTheme = EditorView.baseTheme({
   '&': {
     height: '100%',
   },
   '.cm-scroller': {
     overflow: 'auto',
   },
   '.cm-content': {
     minHeight: '100%',
   },
 });

 export default createGraphiteTheme;

