1. /*
2.  * Graphite — AIChat Styles
3.  */
4. 
5. .ai-chat {
6.   background-color: var(--bg-panel);
7.   display: flex;
8.   flex-direction: column;
9.   height: 100%;
10.   width: 100%;
11.   min-width: 0;
12.   max-width: 100%;
13.   overflow: hidden;
14.   box-sizing: border-box;
15. }
16. 
17. .ai-chat-body {
18.   flex: 1;
19.   display: flex;
20.   flex-direction: column;
21.   gap: 12px;
22.   padding: 16px;
23.   min-height: 0;
24. }
25. 
26. /* Context bar showing current file */
27. .ai-chat-context {
28.   display: flex;
29.   align-items: center;
30.   gap: 8px;
31.   padding: 0 16px 8px;
32.   border-bottom: 1px solid var(--border-subtle);
33. }
34. 
35. .ai-chat-context-label {
36.   font-size: 11px;
37.   color: var(--text-tertiary);
38. }
39. 
40. .ai-chat-file-badge {
41.   font-family: var(--font-mono);
42.   font-size: 11px;
43.   color: var(--text-secondary);
44.   padding: 2px 8px;
45.   background-color: var(--hover);
46.   border-radius: 4px;
47.   max-width: 100%;
48.   overflow: hidden;
49.   text-overflow: ellipsis;
50.   white-space: nowrap;
51. }
52. 
53. /* Messages container */
54. .ai-chat-messages {
55.   flex: 1;
56.   padding: 0;
57.   display: flex;
58.   flex-direction: column;
59.   gap: 16px;
60.   overflow-y: auto;
61.   overflow-x: hidden;
62.   min-width: 0;
63.   box-sizing: border-box;
64. }
65. 
66. /* Individual message */
67. .chat-message {
68.   display: flex;
69.   flex-direction: column;
70.   gap: 6px;
71.   max-width: 85%;
72.   min-width: 0;
73. }
74. 
75. .chat-message.user {
76.   align-self: flex-end;
77.   align-items: flex-end;
78. }
79. 
80. .chat-message.assistant {
81.   align-self: flex-start;
82.   align-items: flex-start;
83. }
84. 
85. .chat-message-label {
86.   font-size: 10px;
87.   font-weight: 600;
88.   text-transform: uppercase;
89.   letter-spacing: 0.08em;
90.   color: var(--text-tertiary);
91. }
92. 
93. .chat-message-content {
94.   padding: 10px 14px;
95.   font-size: 13px;
96.   line-height: 1.5;
97.   word-wrap: break-word;
98.   overflow-wrap: break-word;
99.   word-break: break-word;
100.   white-space: normal;
101.   max-width: 100%;
102. }
103. 
104. .chat-message.user .chat-message-content {
105.   background-color: var(--accent);
106.   color: var(--text-inverse);
107.   border-radius: 12px 12px 2px 12px;
108. }
109. 
110. .chat-message.assistant .chat-message-content {
111.   background-color: var(--bg-secondary);
112.   color: var(--text-primary);
113.   border-radius: 12px 12px 12px 2px;
114. }
115. 
116. /* Input container - unified box */
117. .ai-chat-input-container {
118.   display: flex;
119.   flex-direction: column;
120.   margin: 0;
121.   background-color: var(--bg-secondary);
122.   border: 1px solid var(--border);
123.   border-radius: 10px;
124.   overflow: visible;
125.   transition: border-color var(--transition-fast);
126.   flex-shrink: 0;
127.   position: relative;
128. }
129. 
130. .ai-chat-input-container:focus-within {
131.   border-color: var(--accent);
132. }
133. 
134. .ai-chat-input {
135.   width: 100%;
136.   padding: 12px 14px 8px;
137.   background-color: transparent;
138.   border: none;
139.   font-family: var(--font-body);
140.   font-size: 13px;
141.   line-height: 1.5;
142.   color: var(--text-primary);
143.   resize: none;
144.   min-height: 52px;
145.   max-height: 120px;
146.   box-sizing: border-box;
147. }
148. 
149. .ai-chat-input::placeholder {
150.   color: var(--text-tertiary);
151. }
152. 
153. .ai-chat-input:focus {
154.   outline: none;
155. }
156. 
157. /* Toolbar inside input container */
158. .ai-chat-toolbar {
159.   display: flex;
160.   align-items: center;
161.   justify-content: space-between;
162.   padding: 6px 8px;
163.   border-top: 1px solid var(--border-subtle);
164.   background-color: var(--bg-secondary);
165.   flex-shrink: 0;
166.   gap: 8px;
167.   overflow: visible;
168.   border-radius: 0 0 9px 9px;
169. }
170. 
171. .ai-chat-toolbar-left {
172.   display: flex;
173.   align-items: center;
174.   gap: 8px;
175.   min-width: 0;
176.   flex: 1;
177.   overflow: visible;
178.   position: relative;
179. }
180. 
181. .ai-chat-toolbar-right {
182.   display: flex;
183.   align-items: center;
184.   flex-shrink: 0;
185. }
186. 
187. /* Model picker button */
188. .ai-chat-model-picker {
189.   display: flex;
190.   align-items: center;
191.   gap: 6px;
192.   padding: 4px 10px;
193.   border-radius: 6px;
194.   font-size: 12px;
195.   color: var(--text-secondary);
196.   background-color: transparent;
197.   transition: 
198.     background-color var(--transition-fast),
199.     color var(--transition-fast);
200.   min-width: 0;
201.   overflow: hidden;
202.   cursor: pointer;
203. }
204. 
205. .ai-chat-model-picker span {
206.   overflow: hidden;
207.   text-overflow: ellipsis;
208.   white-space: nowrap;
209. }
210. 
211. .ai-chat-model-picker:hover {
212.   background-color: var(--hover);
213.   color: var(--text-primary);
214. }
215. 
216. .ai-chat-model-picker svg:first-child {
217.   color: var(--accent);
218. }
219. 
220. /* Send button */
221. .ai-chat-send {
222.   display: flex;
223.   align-items: center;
224.   justify-content: center;
225.   width: 28px;
226.   height: 28px;
227.   border-radius: 6px;
228.   background-color: transparent;
229.   color: var(--text-tertiary);
230.   transition: 
231.     background-color var(--transition-fast),
232.     color var(--transition-fast);
233. }
234. 
235. .ai-chat-send.active {
236.   background-color: var(--accent);
237.   color: var(--text-inverse);
238. }
239. 
240. .ai-chat-send.active:hover {
241.   opacity: 0.9;
242. }
243. 
244. .ai-chat-send.stop {
245.   background-color: var(--error-text);
246.   color: var(--text-on-error);
247. }
248. 
249. .ai-chat-send.stop:hover {
250.   opacity: 0.85;
251. }
252. 
253. .ai-chat-send:disabled {
254.   cursor: default;
255.   opacity: 1;
256. }
257. 
258. /* Typing indicator */
259. .typing-indicator {
260.   display: inline-flex;
261.   align-items: center;
262.   gap: 4px;
263. }
264. 
265. .typing-indicator span {
266.   width: 6px;
267.   height: 6px;
268.   background-color: var(--text-tertiary);
269.   border-radius: 50%;
270.   animation: typing-pulse 1.2s ease-in-out infinite;
271. }
272. 
273. .typing-indicator span:nth-child(2) {
274.   animation-delay: 0.2s;
275. }
276. 
277. .typing-indicator span:nth-child(3) {
278.   animation-delay: 0.4s;
279. }
280. 
281. @keyframes typing-pulse {
282.   0%, 60%, 100% {
283.     transform: scale(1);
284.     opacity: 0.4;
285.   }
286.   30% {
287.     transform: scale(1.2);
288.     opacity: 1;
289.   }
290. }
