@@ -1,190 +1,190 @@
 /**
  * Graphite — ThemeSwitcher
  * 
  * Dropdown menu for selecting themes, organized by Dark/Light categories.
  * Shows all 5 built-in themes in a single dropdown.
  */

 import React, { useState, useRef, useEffect, useMemo } from 'react';
 import { useTheme } from '../../hooks/useTheme';
 import { getAllThemes } from '../../themes/theme-registry';
 import { Chevron } from '../../icons/Icons';
 import './ThemeSwitcher.css';

 export default function ThemeSwitcher() {
   const { theme, setThemeByName, userThemes } = useTheme();
   const [isOpen, setIsOpen] = useState(false);
   const containerRef = useRef(null);
   const triggerRef = useRef(null);
   const dropdownRef = useRef(null);
   const [dropdownStyle, setDropdownStyle] = useState({});

   const themesByMode = useMemo(() => {
     const allThemes = Object.values(getAllThemes(userThemes));
     const grouped = { dark: [], light: [] };

     allThemes.forEach((themeItem) => {
       const mode = themeItem.mode === 'light' ? 'light' : 'dark';
       grouped[mode].push({
         id: themeItem.id || themeItem.name,
         name: themeItem.displayName || themeItem.name,
         description: themeItem.description || 'Custom theme',
       });
     });

     grouped.dark.sort((a, b) => a.name.localeCompare(b.name));
     grouped.light.sort((a, b) => a.name.localeCompare(b.name));

     return grouped;
   }, [userThemes]);

   // Close on click outside
   useEffect(() => {
     function handleClickOutside(e) {
       if (containerRef.current && !containerRef.current.contains(e.target)) {
         setIsOpen(false);
       }
     }

     if (isOpen) {
       document.addEventListener('mousedown', handleClickOutside);
       return () => document.removeEventListener('mousedown', handleClickOutside);
     }
   }, [isOpen]);

   // Test hook for automated audits
   useEffect(() => {
     if (typeof window === 'undefined') return undefined;
     const previous = window.__graphiteSetThemeSwitcherOpen;
     window.__graphiteSetThemeSwitcherOpen = setIsOpen;
     if (window.__graphiteOpenThemeSwitcher) {
       setIsOpen(true);
     }
     return () => {
       if (window.__graphiteSetThemeSwitcherOpen === setIsOpen) {
         window.__graphiteSetThemeSwitcherOpen = previous;
       }
     };
   }, []);

   // Position dropdown within the viewport
   useEffect(() => {
     if (!isOpen) return;

     const positionDropdown = () => {
       if (!triggerRef.current || !dropdownRef.current) return;

       const padding = 8;
       const triggerRect = triggerRef.current.getBoundingClientRect();
       const menuRect = dropdownRef.current.getBoundingClientRect();
       const viewportWidth = window.innerWidth;
       const viewportHeight = window.innerHeight;

       // Align right edge to trigger by default
       let left = triggerRect.right - menuRect.width;
       let top = triggerRect.bottom + 4;

       if (left < padding) left = padding;
       if (left + menuRect.width > viewportWidth - padding) {
         left = Math.max(padding, viewportWidth - padding - menuRect.width);
       }

       if (top + menuRect.height > viewportHeight - padding) {
         top = Math.max(padding, viewportHeight - padding - menuRect.height);
       }

       setDropdownStyle({ left: `${left}px`, top: `${top}px` });
     };

     positionDropdown();
     window.addEventListener('resize', positionDropdown);
     window.addEventListener('scroll', positionDropdown, true);

     return () => {
       window.removeEventListener('resize', positionDropdown);
       window.removeEventListener('scroll', positionDropdown, true);
     };
   }, [isOpen]);

   // Close on Escape
   useEffect(() => {
     function handleKeyDown(e) {
       if (e.key === 'Escape') {
         setIsOpen(false);
       }
     }

     if (isOpen) {
       document.addEventListener('keydown', handleKeyDown);
       return () => document.removeEventListener('keydown', handleKeyDown);
     }
   }, [isOpen]);

   const handleSelect = (themeId) => {
     setThemeByName(themeId);
     setIsOpen(false);
   };

   // Get current theme name for display
   const currentThemeName = theme?.displayName || theme?.name || 'Silver';
   const currentThemeId = theme?.name || 'silver';

   return (
     <div className="theme-switcher no-drag" ref={containerRef} data-open={isOpen ? 'true' : 'false'}>
       <button 
         ref={triggerRef}
         className="theme-switcher-trigger hoverable no-drag"
         onClick={() => setIsOpen(!isOpen)}
         aria-expanded={isOpen}
         aria-haspopup="listbox"
       >
         <span className="theme-switcher-current">{currentThemeName}</span>
         <Chevron size={12} className={`theme-switcher-chevron ${isOpen ? 'open' : ''}`} />
       </button>

       {isOpen && (
         <div 
           ref={dropdownRef}
           className="theme-switcher-dropdown no-drag" 
           role="listbox"
           style={dropdownStyle}
         >
           <div className="theme-switcher-group">
             <span className="theme-switcher-group-label">Dark</span>
             {themesByMode.dark.map((t) => (
               <button
                 key={t.id}
                 className={`theme-switcher-option hoverable ${t.id === currentThemeId ? 'active' : ''}`}
                 onClick={() => handleSelect(t.id)}
                 role="option"
                 aria-selected={t.id === currentThemeId}
               >
                 <span className="theme-option-name">{t.name}</span>
                 <span className="theme-option-description">{t.description}</span>
               </button>
             ))}
           </div>

           <div className="theme-switcher-divider" />

           <div className="theme-switcher-group">
             <span className="theme-switcher-group-label">Light</span>
             {themesByMode.light.map((t) => (
               <button
                 key={t.id}
                 className={`theme-switcher-option hoverable ${t.id === currentThemeId ? 'active' : ''}`}
                 onClick={() => handleSelect(t.id)}
                 role="option"
                 aria-selected={t.id === currentThemeId}
               >
                 <span className="theme-option-name">{t.name}</span>
                 <span className="theme-option-description">{t.description}</span>
               </button>
             ))}
           </div>
         </div>
       )}
     </div>
   );
 }

