1. /**
2.  * Graphite — FileNode
3.  * 
4.  * A single file or folder in the file tree.
5.  * Folders can expand/collapse to show children.
6.  * Supports context menu and inline rename.
7.  */
8. 
9. import React, { useState, useRef, useEffect } from 'react';
10. import { Chevron, Folder, FolderOpen, File } from '../../icons/Icons';
11. import FileContextMenu from './FileContextMenu';
12. 
13. export default function FileNode({ 
14.   node, 
15.   depth = 0, 
16.   currentFile, 
17.   onFileSelect,
18.   onRename,
19.   onDelete,
20.   onNewFile,
21.   onNewFolder,
22.   searchQuery = '',
23.   pendingRenamePath = null,
24.   onRenameComplete = null,
25. }) {
26.   const [isExpanded, setIsExpanded] = useState(depth < 2);
27.   const [isRenaming, setIsRenaming] = useState(false);
28.   const [renameValue, setRenameValue] = useState(node.name);
29.   const [contextMenu, setContextMenu] = useState(null);
30.   const inputRef = useRef(null);
31.   const hasTriggeredRename = useRef(false);
32.   
33.   const isFolder = node.type === 'folder';
34.   const isActive = currentFile === node.path;
35.   const hasChildren = isFolder && node.children && node.children.length > 0;
36.   
37.   // Auto-start rename mode for newly created items (only once)
38.   useEffect(() => {
39.     if (pendingRenamePath && node.path === pendingRenamePath && !hasTriggeredRename.current) {
40.       hasTriggeredRename.current = true;
41.       setRenameValue(node.name);
42.       setIsRenaming(true);
43.     }
44.     // Reset the trigger flag when pendingRenamePath clears
45.     if (!pendingRenamePath) {
46.       hasTriggeredRename.current = false;
47.     }
48.   }, [pendingRenamePath, node.path, node.name]);
49.   
50.   // Filter logic for search
51.   const matchesSearch = !searchQuery || 
52.     node.name.toLowerCase().includes(searchQuery.toLowerCase());
53.   
54.   // For folders, check if any descendant matches
55.   const hasMatchingDescendant = isFolder && searchQuery && 
56.     hasDescendantMatch(node, searchQuery);
57.   
58.   // Hide if doesn't match and no matching descendants
59.   if (searchQuery && !matchesSearch && !hasMatchingDescendant) {
60.     return null;
61.   }
62.   
63.   // Auto-expand folders with matching descendants during search
64.   const shouldShowChildren = searchQuery ? hasMatchingDescendant : isExpanded;
65. 
66.   // Focus input when renaming starts (only runs once when isRenaming becomes true)
67.   useEffect(() => {
68.     if (isRenaming && inputRef.current) {
69.       inputRef.current.focus();
70.       // Select filename without extension for files
71.       if (!isFolder) {
72.         const lastDot = node.name.lastIndexOf('.');
73.         if (lastDot > 0) {
