 import React, { useState, useRef, useEffect } from 'react';
 import { Chevron, Folder, FolderOpen, File } from '../../icons/Icons';
 import FileContextMenu from './FileContextMenu';

 export default function FileNode({ 
   node, 
   depth = 0, 
   currentFile, 
   onFileSelect,
   onRename,
   onDelete,
   onNewFile,
   onNewFolder,
   searchQuery = '',
   pendingRenamePath = null,
   onRenameComplete = null,
 }) {
   const [isExpanded, setIsExpanded] = useState(depth < 2);
   const [isRenaming, setIsRenaming] = useState(false);
   const [renameValue, setRenameValue] = useState(node.name);
   const [contextMenu, setContextMenu] = useState(null);
   const inputRef = useRef(null);
   const hasTriggeredRename = useRef(false);

   const isFolder = node.type === 'folder';
   const isActive = currentFile === node.path;
   const hasChildren = isFolder && node.children && node.children.length > 0;

   // Auto-start rename mode for newly created items (only once)
   useEffect(() => {
     if (pendingRenamePath && node.path === pendingRenamePath && !hasTriggeredRename.current) {
       hasTriggeredRename.current = true;
       setRenameValue(node.name);
       setIsRenaming(true);
     }
     // Reset the trigger flag when pendingRenamePath clears
     if (!pendingRenamePath) {
       hasTriggeredRename.current = false;
     }
   }, [pendingRenamePath, node.path, node.name]);

