   const matchesSearch = !searchQuery || 
     node.name.toLowerCase().includes(searchQuery.toLowerCase());

   // For folders, check if any descendant matches
   const hasMatchingDescendant = isFolder && searchQuery && 
     hasDescendantMatch(node, searchQuery);

   // Hide if doesn't match and no matching descendants
   if (searchQuery && !matchesSearch && !hasMatchingDescendant) {
     return null;
   }

   // Auto-expand folders with matching descendants during search
   const shouldShowChildren = searchQuery ? hasMatchingDescendant : isExpanded;

   // Focus input when renaming starts (only runs once when isRenaming becomes true)
   useEffect(() => {
     if (isRenaming && inputRef.current) {
       inputRef.current.focus();
       // Select filename without extension for files
       if (!isFolder) {
         const lastDot = node.name.lastIndexOf('.');
         if (lastDot > 0) {
           inputRef.current.setSelectionRange(0, lastDot);
