     const trimmedValue = renameValue.trim();
     if (trimmedValue && trimmedValue !== node.name) {
       await onRename(node.path, trimmedValue);
     }
     setIsRenaming(false);
     onRenameComplete?.();
   };

   const handleRenameKeyDown = (e) => {
     if (e.key === 'Enter') {
       e.preventDefault();
       handleRenameSubmit();
     } else if (e.key === 'Escape') {
       setRenameValue(node.name);
       setIsRenaming(false);
       onRenameComplete?.();
     }
   };

   const handleDelete = async () => {
     // Simple confirmation
     const itemType = isFolder ? 'folder' : 'file';
     const confirmed = window.confirm(`Move "${node.name}" to Trash?`);
     if (confirmed) {
       await onDelete(node.path);
     }
   };

