 /**
  * Graphite — StatusBar Component
  * 
  * Height: 32px
  * - Left: word count · char count · read time
  * - Right: current file path
  */

 import React, { useMemo } from 'react';
 import './StatusBar.css';

 export default function StatusBar({ wordCount = 0, charCount = 0, filePath = null, focusMode = 'off' }) {
   // Calculate estimated read time (assuming 200 words per minute)
   const readTime = useMemo(() => {
     if (wordCount === 0) return '0 min read';
     const minutes = Math.ceil(wordCount / 200);
     return minutes === 1 ? '1 min read' : `${minutes} min read`;
   }, [wordCount]);

   // Format file path for display (show relative path if possible)
   const displayPath = useMemo(() => {
     if (!filePath) return 'No file open';
     // Show last 2-3 path segments for context
     const segments = filePath.split('/');
     if (segments.length <= 3) return filePath;
     return '.../' + segments.slice(-3).join('/');
   }, [filePath]);

   // Focus mode label
   const focusLabel = useMemo(() => {
     if (focusMode === 'typewriter') return 'Typewriter';
     if (focusMode === 'sentence') return 'Sentence Focus';
     return null;
   }, [focusMode]);

   return (
     <footer className="status-bar">
       <div className="status-bar-left">
         <span className="status-item">{wordCount.toLocaleString()} words</span>
         <span className="status-separator">·</span>
         <span className="status-item">{charCount.toLocaleString()} chars</span>
         <span className="status-separator">·</span>
         <span className="status-item">{readTime}</span>
         {focusLabel && (
           <>
             <span className="status-separator">·</span>
             <span className="status-item status-focus-mode">{focusLabel}</span>
           </>
         )}
       </div>
       <div className="status-bar-right">
         <span className="status-path">{displayPath}</span>
       </div>
     </footer>
   );
 }

