 /*
  * Graphite — PanelHeader Styles
  */

 .panel-header {
   display: flex;
   align-items: center;
   gap: 8px;
   padding: 0 16px;
   flex-shrink: 0;
   user-select: none;
   height: 44px;
   min-height: 44px;
   overflow: hidden;
   min-width: 0;
 }

 .panel-header.draggable {
   cursor: grab;
   /* Reserve space for drag handle so titles align */
   padding-left: 12px;
 }

 .panel-header.draggable:active {
   cursor: grabbing;
 }

 .panel-header.dragging {
   opacity: 0.5;
 }

 .panel-drag-handle {
   display: flex;
   align-items: center;
   justify-content: center;
   width: 12px;
   color: var(--text-tertiary);
   opacity: 0;
   transition: opacity var(--transition-fast);
   flex-shrink: 0;
 }

 .panel-header:hover .panel-drag-handle {
   opacity: 1;
 }

 .panel-header.dragging .panel-drag-handle {
   opacity: 1;
 }

 /* Non-draggable panels get same padding for alignment */
 .panel-header:not(.draggable) {
   padding-left: 32px; /* 12px padding + 12px handle + 8px gap */
 }

 /* Panel icon */
 .panel-icon {
   flex-shrink: 0;
 }

 /* Panel title */
 .panel-title {
   white-space: nowrap;
   overflow: hidden;
   text-overflow: ellipsis;
   min-width: 0;
   flex: 1;
 }

 /* Spacer to push elements right */
 .panel-header-spacer {
   flex: 1;
   min-width: 8px;
 }

 /* Drop zone indicator */
 .panel-wrapper.drag-over {
   position: relative;
 }

 .panel-wrapper.drag-over::before {
   content: '';
   position: absolute;
   top: 0;
   left: 0;
   width: 3px;
   height: 100%;
   background-color: var(--accent);
   z-index: 10;
 }

