 const { app, BrowserWindow, ipcMain, dialog, nativeTheme, Menu } = require('electron');
 const path = require('path');
 const fs = require('fs');
 const os = require('os');
 const { aiClient } = require('./ai-client');

 // Set app name for macOS menu bar (must be before app ready)
 if (process.platform === 'darwin') {
   app.setName('Graphite');
   // Show dock icon for the main app (LSUIElement hides it by default
   // so that Copilot CLI subprocesses don't get their own dock icon)
   app.dock?.show();
 }

 let mainWindow = null;

 // ============================================================
 // User data paths and utilities
 // ============================================================

 const userDataPath = app.getPath('userData');
 const userThemesDir = path.join(app.getPath('home'), '.graphite', 'themes');
 const preferencesPath = path.join(userDataPath, 'preferences.json');
 const feedbackIssuesApiUrl = 'https://api.github.com/repos/jayparikh/graphite-release/issues';

 function getFeedbackToken() {
   if (typeof __GITHUB_FEEDBACK_TOKEN__ !== 'undefined' && __GITHUB_FEEDBACK_TOKEN__) {
     return __GITHUB_FEEDBACK_TOKEN__.trim();
   }
   return (process.env.VITE_GITHUB_FEEDBACK_TOKEN || '').trim();
 }

 function getPlatformName() {
   if (process.platform === 'darwin') return 'macOS';
   if (process.platform === 'win32') return 'Windows';
   return 'Linux';
 }

 function buildFeedbackIssueBody({ type, description, email }) {
   const contact = email?.trim();
   const typeLabel = type === 'feature' ? 'Feature Request' : 'Bug Report';
   return [
     description.trim(),
     '',
     '---',
     `**Type:** ${typeLabel}`,
     `**App Version:** ${app.getVersion()}`,
     `**OS:** ${getPlatformName()} ${os.release()} (${os.arch()})`,
     contact ? `**Contact:** ${contact}` : null,
   ]

