   await expect(autoApplyOff).toHaveClass(/active/);

   // Toggle Diff preview on — verify active class
   const diffSection = modal.locator('.settings-row').filter({ hasText: 'Diff preview' });
   const diffOn = diffSection.locator('.settings-toggle-option', { hasText: 'On' });
   await diffOn.click();
   await expect(diffOn).toHaveClass(/active/);

   // Change reasoning effort
   await reasoningSelect.selectOption('high');
   await expect(reasoningSelect).toHaveValue('high');

